from __future__ import annotations

import argparse
import csv
import os
import re
import sys
from dataclasses import asdict, dataclass
from typing import Dict, List, Optional, Tuple

"""Simplified training-log parser + plotter.

Parses epochs, total loss, and AU metrics (acc/f1/score) from logs that contain lines like:
    - 'Training AU, Epoch:<n>'
    - 'Train Total Loss,<val>, ...'
    - 'Training,AU, Epoch:<n>, AU:acc:<a>, f1:<f>, score:<s>'

Usage examples:
    1) Use the historical default path:
         python show_loss.py

    2) Plot your own log file (recommended):
         python show_loss.py --log /abs/path/to/hrformer_A;V_log.txt --only-acc-f1

Outputs (by default) go to 'results/pic/'.
"""


EPOCH_START_RE = re.compile(r"Epoch:(\d+)")
TOTAL_LOSS_RE = re.compile(r"Train Total Loss,([0-9.eE+-]+)")
AU_METRICS_RE = re.compile(r"AU:acc:([0-9.]+), f1:([0-9.]+), score:([0-9.]+)")


@dataclass
class EpochRecord:
    epoch: int
    total_loss: Optional[float] = None
    acc: Optional[float] = None
    f1: Optional[float] = None
    score: Optional[float] = None

    def update_loss(self, loss: float):
        self.total_loss = loss

    def update_metrics(self, acc: float, f1: float, score: float):
        self.acc = acc
        self.f1 = f1
        self.score = score


def parse_log(path: str) -> Dict[int, EpochRecord]:
    """Parse the training log file and return a mapping epoch -> EpochRecord.

    Strategy:
      1. Track the most recently announced epoch via lines containing 'Epoch:<n>'.
      2. A subsequent 'Train Total Loss,<val>' line is attributed to that current epoch.
      3. A 'Training,AU, Epoch:<n>, AU:acc:..., f1:..., score:...' line supplies metrics.
    """
    if not os.path.isfile(path):
        raise FileNotFoundError(f"Log file not found: {path}")

    records: Dict[int, EpochRecord] = {}
    current_epoch: Optional[int] = None

    with open(path, "r", encoding="utf-8", errors="ignore") as f:
        for raw_line in f:
            line = raw_line.strip()
            if not line:
                continue

            # Detect epoch start marker
            m_epoch = EPOCH_START_RE.search(line)
            if m_epoch:
                current_epoch = int(m_epoch.group(1))
                records.setdefault(current_epoch, EpochRecord(epoch=current_epoch))

            # Total loss line
            if "Train Total Loss" in line:
                m_loss = TOTAL_LOSS_RE.search(line)
                if m_loss and current_epoch is not None:
                    loss_val = float(m_loss.group(1))
                    records.setdefault(current_epoch, EpochRecord(epoch=current_epoch)).update_loss(loss_val)
                continue

            # Metrics line
            if "Training,AU" in line:
                # Some lines re-include Epoch:<n>, prefer explicit epoch if present
                m_epoch2 = EPOCH_START_RE.search(line)
                epoch_for_metrics = current_epoch
                if m_epoch2:
                    epoch_for_metrics = int(m_epoch2.group(1))
                m_metrics = AU_METRICS_RE.search(line)
                if m_metrics and epoch_for_metrics is not None:
                    acc, f1, score = map(float, m_metrics.groups())
                    records.setdefault(epoch_for_metrics, EpochRecord(epoch=epoch_for_metrics)).update_metrics(acc, f1, score)

    return records


def summarize(records: Dict[int, EpochRecord]) -> str:
    if not records:
        return "No epoch data parsed."
    epochs = sorted(records.keys())
    # Build lists with non-None values only; type now List[tuple[int, float]]
    losses: List[Tuple[int, float]] = [
        (e, records[e].total_loss)  # type: ignore[arg-type]
        for e in epochs if records[e].total_loss is not None
    ]  # each total_loss is non-None now
    if not losses:
        return "No loss values parsed."
    best_loss_epoch, best_loss = min(losses, key=lambda x: x[1])
    return f"Best (min) loss {best_loss:.6f} at epoch {best_loss_epoch}"


def save_csv(records: Dict[int, EpochRecord], csv_path: str):
    fieldnames = ["epoch", "total_loss", "acc", "f1", "score"]
    os.makedirs(os.path.dirname(csv_path) or ".", exist_ok=True)
    with open(csv_path, "w", newline="", encoding="utf-8") as f:
        writer = csv.DictWriter(f, fieldnames=fieldnames)
        writer.writeheader()
        for e in sorted(records.keys()):
            writer.writerow(asdict(records[e]))


def try_plot(records: Dict[int, EpochRecord], out_dir: Optional[str] = None, show: bool = False, title: str = "Training Metrics"):
    try:
        import matplotlib.pyplot as plt  # type: ignore
    except Exception as exc:  # pragma: no cover - optional dep
        print(f"[WARN] matplotlib not available, skipping plots ({exc})", file=sys.stderr)
        return

    epochs = sorted(records.keys())
    losses = [records[e].total_loss for e in epochs]
    accs = [records[e].acc for e in epochs]
    f1s_vals = [records[e].f1 for e in epochs]
    scores = [records[e].score for e in epochs]

    fig, axes = plt.subplots(2, 1, figsize=(8, 8), sharex=True)
    ax_loss, ax_metrics = axes
    ax_loss.plot(epochs, losses, marker='o', label='Total Loss')
    # annotate best (minimum) loss if available
    loss_pairs = [(e, records[e].total_loss) for e in epochs if records[e].total_loss is not None]
    if loss_pairs:
        best_epoch, best_loss = min(loss_pairs, key=lambda x: x[1])  # type: ignore[return-value]
        ax_loss.scatter([best_epoch], [best_loss], s=50)
        ax_loss.annotate(
            f"best loss\n{best_loss:.4f} @ {best_epoch}",
            (best_epoch, best_loss),
            textcoords="offset points",
            xytext=(8, 8),
        )
    ax_loss.set_ylabel('Loss')
    ax_loss.grid(True, alpha=0.3)
    ax_loss.legend()

    if any(v is not None for v in accs):
        ax_metrics.plot(epochs, accs, label='AU Acc', alpha=0.8)
    if any(v is not None for v in f1s_vals):
        ax_metrics.plot(epochs, f1s_vals, label='AU F1', alpha=0.8)
    if any(v is not None for v in scores):
        ax_metrics.plot(epochs, scores, label='AU Score', alpha=0.8)
    ax_metrics.set_xlabel('Epoch')
    ax_metrics.set_ylabel('Metric Value')
    ax_metrics.grid(True, alpha=0.3)
    ax_metrics.legend()
    fig.suptitle(title)
    fig.tight_layout(rect=(0.0, 0.0, 1.0, 0.97))

    if out_dir:
        os.makedirs(out_dir, exist_ok=True)
        png_path = os.path.join(out_dir, "training_metrics.png")
        fig.savefig(png_path, dpi=150)
        print(f"Saved plot: {png_path}")
    if show:
        plt.show()
    else:
        plt.close(fig)


def _safe_stem(name: str) -> str:
    stem, _ext = os.path.splitext(name)
    # Avoid creating odd filenames when log basenames contain separators/spaces.
    stem = stem.replace(os.sep, "_").replace(" ", "_")
    return stem


def _best_point(pairs: List[Tuple[int, float]]) -> Optional[Tuple[int, float]]:
    if not pairs:
        return None
    return max(pairs, key=lambda x: x[1])


def _pairs_from_records(records: Dict[int, EpochRecord], field: str) -> List[Tuple[int, float]]:
    pairs: List[Tuple[int, float]] = []
    for e in sorted(records.keys()):
        v = getattr(records[e], field)
        if v is None:
            continue
        pairs.append((e, float(v)))
    return pairs


def plot_acc_f1(records: Dict[int, EpochRecord], out_dir: str, show: bool = False, title: str = "AU Acc/F1"):
    try:
        import matplotlib.pyplot as plt  # type: ignore
    except Exception as exc:  # pragma: no cover - optional dep
        print(f"[WARN] matplotlib not available, skipping plots ({exc})", file=sys.stderr)
        return

    acc_pairs = _pairs_from_records(records, "acc")
    f1_pairs = _pairs_from_records(records, "f1")

    fig, ax = plt.subplots(1, 1, figsize=(10, 4.5))
    if acc_pairs:
        xs, ys = zip(*acc_pairs)
        ax.plot(xs, ys, marker="o", markersize=3, label="AU Acc", alpha=0.85)
    if f1_pairs:
        xs, ys = zip(*f1_pairs)
        ax.plot(xs, ys, marker="o", markersize=3, label="AU F1", alpha=0.85)

    # If loss exists in the log, show the best (minimum) loss as text.
    loss_pairs = _pairs_from_records(records, "total_loss")
    if loss_pairs:
        best_epoch, best_loss = min(loss_pairs, key=lambda x: x[1])
        ax.text(
            0.98,
            0.98,
            f"best loss\n{best_loss:.4f} @ {best_epoch}",
            transform=ax.transAxes,
            ha="right",
            va="top",
            bbox=dict(boxstyle="round,pad=0.3", facecolor="white", alpha=0.8),
        )

    ax.set_xlabel("Epoch")
    ax.set_ylabel("Value")
    ax.set_ylim(0.0, 1.0)
    ax.grid(True, alpha=0.3)
    ax.legend()
    ax.set_title(title)
    fig.tight_layout()

    os.makedirs(out_dir, exist_ok=True)
    png_path = os.path.join(out_dir, "acc_f1.png")
    fig.savefig(png_path, dpi=150)
    print(f"Saved plot: {png_path}")
    if show:
        plt.show()
    else:
        plt.close(fig)


LOG_PATH = os.path.join("experiments", "super", "HRFormer_lr1e-3", "hrformer_A;V_log.txt")
OUT_DIR = os.path.join("results", "pic")


def _parse_args(argv: Optional[List[str]] = None) -> argparse.Namespace:
    p = argparse.ArgumentParser()
    p.add_argument("--log", default=LOG_PATH, help="Path to the training log file")
    p.add_argument("--out-dir", default=OUT_DIR, help="Directory to save CSV/plots")
    p.add_argument("--show", action="store_true", help="Show plot windows (matplotlib GUI)")
    p.add_argument(
        "--only-acc-f1",
        action="store_true",
        help="Only plot AU acc/f1 (skip the loss+metrics 2-panel plot)",
    )
    return p.parse_args(argv)


def run_cli(argv: Optional[List[str]] = None) -> int:
    args = _parse_args(argv)
    log_path = args.log

    if not os.path.isfile(log_path):
        print(f"ERROR: Log file not found: {log_path}", file=sys.stderr)
        return 2

    records = parse_log(log_path)
    if not records:
        print("No data parsed. Check the log file format.", file=sys.stderr)
        return 1

    print(f"Parsed {len(records)} epochs from {log_path}")
    print(summarize(records))

    os.makedirs(args.out_dir, exist_ok=True)
    stem = _safe_stem(os.path.basename(log_path))
    csv_path = os.path.join(args.out_dir, f"{stem}_metrics.csv")
    save_csv(records, csv_path)
    print(f"Saved CSV: {csv_path}")

    title = os.path.basename(log_path)
    try:
        if args.only_acc_f1:
            plot_acc_f1(records, out_dir=args.out_dir, show=args.show, title=title)
        else:
            try_plot(records, out_dir=args.out_dir, show=args.show, title=title)
    except Exception as e:  # pragma: no cover
        print(f"[WARN] Plotting failed: {e}", file=sys.stderr)
    return 0


